tle": "Hospitality Industry", "skills/5/title": "Hotel Management", "skills/6/title": "Hospitality Management", "skills/7/title": "Food & Beverage", "skills/8/title": "Hotels", "skills/9/title": "Banquets", "skills/10/title": "Fine Dining", "skills/11/title": "Restaurants", "skills/12/title": "Event Management", "skills/13/title": "Restaurant Management", "skills/14/title": "Tourism", "skills/15/title": "Front Office", "skills/16/title": "Event Planning", "skills/17/title": "Menu Development", "skills/18/title": "Customer Satisfaction", "skills/19/title": "Cuisine", "totalExperienceYears": "21.3", "totalRecommendationsGiven": "4", "totalRecommendationsReceived": "16", "updates/0/postLink": "https://www.linkedin.com/feed/update/urn:li:activity:7192099129580294144?updateEntityUrn=urn%3Ali%3Afs_feedUpdate%3A%28V2%2Curn%3Ali%3Aactivity%3A7192099129580294144%29", "updates/0/postText": "\"OFF THE MENU\" by our Executive Sous Chef Aphichat Amatmontri\n\nExplore Chef Tun unique Thai-style creations using fresh ingredients from the resort's on-site organic Iris Farm. Alongside Sustainability Supervisor Payap \"Pong\" Khunkayan, they delve into the resort's #farmtotable concept, blending gourmet cuisine with sustainable practices. Discover how Chef Tun's Buddhist principles inspire his culinary art.\n\n#ConradKohSamui #Hilton #OffTheMenu #CulinaryExcellence #SustainableDining", "updates/0/type": "Post", "updates/1/postLink": "https://www.linkedin.com/feed/update/urn:li:activity:7174325365811634179?updateEntityUrn=urn%3Ali%3Afs_feedUpdate%3A%28V2%2Curn%3Ali%3Aactivity%3A7174325365811634179%29", "updates/1/postText": "Thank you Maldives!\n \nI found myself both excited and bittersweet in bidding farewell to our beloved team and the most amazing hotel, Waldorf Astoria Maldives Ithaafushi.\n \nIt has been an incredible journey working alongside talented individuals, crafting unforgettable experiences for our guests. Over the last two years+, I have witnessed firsthand our team's dedication, professionalism, and unwavering commitment to delivering true Maldivian hospitality with an amazing leadership team.\n \nI want to express my deepest appreciation to the WAMI team for your hard work, passion, and outstanding support throughout my tenure, your dedication has been exceptional and made me a better professional. I enjoyed every moment of working alongside you.\n \nFor now, I look forward to writing new chapters in my Hospitality journey, so stay tuned!\n \n“Obrigado e Até breve\"\nMA\n \n#WaldorfAstoriaMaldives #Hilton", "updates/1/type": "Post", "updates/2/image": "https://media.licdn.com/dms/image/v2/D562DAQFHQuiAp7Xi0g/profile-treasury-image-shrink_8192_8192/profile-treasury-image-shrink_8192_8192/0/1665805111235?e=1777395600&v=beta&t=DR0ck73xoNtEG8TwOE4tkTen4BLVekMgUJBH9tQ0p9g", "updates/2/postLink": "https://www.linkedin.com/in/marcomatosaraujo/overlay/1635504888966/single-media-viewer?type=LINK&profileId=ACoAAANhXkIBVaL_YUHUNrUdR2ZLUObDXo0bczc", "updates/2/postText": "Luxury Private Island Maldives \n\nWhatever your heart desires, consider it done on this extraordinary,  island in the necklace of jewels known as the Maldives. Find yourself pampered beyond your wildest expectations in luxury, style and grace. Ithaafushi - The Private Island is your disappearing act into a world you may have imagined, but never realized, could exist.", "updates/2/subTitle": "Ithaafushi - The Private Island", "updates/2/title": "Ithaafushi - The Private Island", "updates/2/type": "Link", "urn": "ACoAAANhXkIBVaL_YUHUNrUdR2ZLUObDXo0bczc", "volunteerAndAwards/0/duration/months": "0", "volunteerAndAwards/0/duration/years": "0", "volunteerAndAwards/0/end_date/month": "0", "volunteerAndAwards/0/end_date/year": "0", "volunteerAndAwards/0/industry": "Civil_rights", "volunteerAndAwards/0/is_current_position": "true", "volunteerAndAwards/0/organization": "MCE Volunteer Team", "volunteerAndAwards/0/role": "Volunteer", "volunteerAndAwards/0/start_date/month": "0", "v